import { Component, h, Prop } from '@stencil/core';
import { RenderCardContent } from '../../utils/card-content-renderer';
import { HeadingLevel } from '../../models/card.model';

@Component({
  tag: 'wdpr-card-small-content',
  shadow: true,
})
export class WdprCardSmallContent {
  @Prop() primaryHeadline: string;
  @Prop() body: string;
  @Prop() bullets: string[];
  @Prop() contentType: 'stacked' | 'body' = 'stacked';
  @Prop() disabled: boolean = false;
  @Prop() inverseColor: boolean = false;
  @Prop({ attribute: 'heading-level' }) headingLevel: HeadingLevel = 'h3';

  render() {
    const props = {
      contentType: this.contentType,
      body: this.body,
      bullets: this.bullets,
      primaryHeadline: this.primaryHeadline,
      headingLevel: this.headingLevel,
      inverseColor: this.inverseColor,
    };

    return (
      <RenderCardContent disabled={this.disabled} variant='small' {...props} />
    );
  }
}